const axios = require('axios');
const cheerio = require('cheerio');

const ALLOWLIST = [
  'https://example.com',
  // Add other allowed URLs here
];

function isValidUrl(url) {
  const urlPattern = /^(http|https):\/\/[^\s/$.?#].[^\s]*$/;
  if (!urlPattern.test(url)) return false;

  const parsedUrl = new URL(url);
  if (ALLOWLIST.includes(parsedUrl.origin)) return true;

  const privateIpRanges = [
    '127.0.0.1',
    '192.168.',
    '10.'
  ];

  for (const range of privateIpRanges) {
    if (parsedUrl.hostname.startsWith(range)) return false;
  }

  return true;
}

async function fetchMetadata(url) {
  if (!isValidUrl(url)) throw new Error('Invalid URL');

  try {
    const response = await axios.get(url);
    const $ = cheerio.load(response.data);

    const metadata = {
      title: $('title').text().trim() || '',
      description: $('meta[name="description"]').attr('content') || '',
      openGraph: {}
    };

    $('meta[property^="og:"]').each((index, element) => {
      const property = $(element).attr('property');
      const content = $(element).attr('content');
      if (property && content) metadata.openGraph[property.replace('og:', '')] = content;
    });

    return metadata;
  } catch (error) {
    throw new Error(`Failed to fetch metadata: ${error.message}`);
  }
}

